<template>
  <div class="my-popups">
    <loader :is-visible="isLoading"></loader>

    <div class="modal d-block">
      <div class="modal-dialog modal-dialog-centered">
        <div class="modal-content">

          <div class="modal-header theme-primary partition-full d-flex">
            <h4 class="modal-title">{{ $t('Set Dates') }}</h4>
            <button type="button" class="close" @click="Close">
              <em class="fa fa-times"></em>
            </button>
          </div>

          <div class="modal-body">
            <dynamic-form
              lang="en"
              ref="ResourceRate"
              :buttons="buttons"
              :schema="FormSchema"
              :mandatorytext="MandatoryString"
              @OnSubmit="onSubmit">
            </dynamic-form>
          </div>

        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  props: {
    EditData: {
      type: Array,
      required: false,
      default: () => []
    }
  },

  data() {
    return {
      isLoading: false,
      MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',

      FormSchema: [
        {
          layoutType: "double",
          Data: [
            {
              astype: "DateField",
              label: this.$t('Start Date (M/D/YYYY)'),
              name: "StartDate",
              value: "",
              placeholder: this.$t('Start Date (M/D/YYYY)'),
              config: { format: "MM/DD/YYYY" },
              validationRules: { required: true },
              disabled: false
            },
            {
              astype: "DateField",
              label: this.$t('End Date (M/D/YYYY)'),
              name: "EndDate",
              value: "",
              placeholder: this.$t('End Date (M/D/YYYY)'),
              config: { format: "MM/DD/YYYY" },
              validationRules: { required: true },
              disabled: false
            }
          ]
        }
      ],

      buttons: [
        {
          type: "submit",
          class: "btn btn-success",
          text: "<i class='fa fa-save pr-2'></i>Set New Dates"
        }
      ]
    };
  },

  watch: {
    EditData: {
      immediate: true,
      deep: true,
      handler(val) {
        if (!val || !val.length) return;

        const firstRow = val[0];
        
        // Directly use the values without new Date()
        this.FormSchema[0].Data[0].value = 
          firstRow.New_Start_Date || "";

        this.FormSchema[0].Data[1].value = 
          firstRow.New_End_Date || "";
      }
    }
  },

  methods: {
    async onSubmit(formfields) {
      const vm = this;

      const isValid = await vm.$refs.ResourceRate.validateForm.validate();
      if (!isValid) return;

      // Prepare data with formatted dates
      const updatedData = {
        startDate: formfields.StartDate,
        endDate: formfields.EndDate
      };

      // Emit event to parent with the new dates
      vm.$emit('dates-updated', updatedData);
      vm.Close();
    },

      Close() {
            this.$parent.isSetDate=false;
        }
  }
};
</script>